/**
 * Lookup helpers — companions to the host shop.ts helpers.
 */
export function getExtendedProduct(slug: string): ShopProduct | undefined {
  return EXTENDED_CATALOG.find((p) => p.slug === slug);
}

export function getExtendedProductsByCategory(category: string): ShopProduct[] {
  return EXTENDED_CATALOG.filter((p) => p.category === category);
}
